// PostGraphQL is the exported counterpart used by smoke tests in other
// packages that want to reuse the harness's HTTP entry point.
func PostGraphQL(h http.Handler, query string, variables map[string]any) error {
	resp, err := postGraphQL(h, query, variables)
	if err != nil {
		return err
	}
	if len(resp.Errors) > 0 {
		return fmt.Errorf("graphql errors: %+v", resp.Errors)
	}
	return nil
}

func percentileMillis(samples []time.Duration) Percentiles {
	if len(samples) == 0 {
		return Percentiles{}
	}
	sort.Slice(samples, func(i, j int) bool { return samples[i] < samples[j] })
	return Percentiles{
		P50: toMillis(percentile(samples, 50)),
		P95: toMillis(percentile(samples, 95)),
		P99: toMillis(percentile(samples, 99)),
	}
}

func percentile(sorted []time.Duration, pct int) time.Duration {
	if len(sorted) == 0 {
		return 0
	}
	idx := (len(sorted)*pct + 99) / 100
	if idx < 1 {
		idx = 1
	}
	if idx > len(sorted) {
		idx = len(sorted)
	}
	return sorted[idx-1]
}

func toMillis(d time.Duration) float64 {
	return float64(d.Microseconds()) / 1000.0
}

// Package perf provides a reusable GraphQL performance harness for the DDx
// server. It seeds realistic on-disk fixtures (projects × beads, docgraph,
// agent sessions) using the real storage primitives, then drives each GraphQL
// query shape through both the in-process StateProvider and the full HTTP
// handler while recording p50/p95/p99 latencies.
//
// The harness exists so performance work can be grounded in numbers rather
// than anecdote (ddx-9ce6842a Part 1). New query shapes are added by
// appending to the target table in harness.go — the fixture and measurement
// layers stay unchanged.
package perf

import (
	"encoding/json"
	"fmt"
	"net/http"
	"os"
	"path/filepath"
	"runtime"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/server"
)

// BeadFixtureSpec describes the shape of a generated workspace.
//
// The defaults (10 projects × 500 beads = 5,000 beads) match the ddx-9ce6842a
// acceptance criteria §5, and the per-query floor of ≥1,000 records documented
// in the 2026-04-22 user directive on fixture size. Consumers that want a
// heavier run should raise BeadsPerProject rather than Projects so the
// distribution stays comparable.
type BeadFixtureSpec struct {
	// Projects is the number of registered projects. Must be ≥ 1.
	Projects int
	// BeadsPerProject is the number of beads seeded in each project.
	// Combined with Projects this yields the total bead corpus size.
	BeadsPerProject int
	// ClosedRatio (0..1) controls the fraction of seeded beads written with
	// status=closed. Defaults to 0.3. A realistic mix matters because
	// status=open filters are the common fast-path.
	ClosedRatio float64
	// LabelDensity is the number of labels assigned per bead. Defaults to 2.
	LabelDensity int
	// AgentSessionsPerProject is the number of agent-session rows seeded into
	// each project's sessions.jsonl file. 0 means "do not seed sessions" —
	// the sessions harness target will still run but report against the
	// naturally-empty feed.
	AgentSessionsPerProject int
	// DocGraphFilesPerProject is the number of stub markdown files seeded
	// into each project so the DocGraph target exercises real IO. 0 means
	// the harness uses only whatever files already exist under the server's
	// working directory.
	DocGraphFilesPerProject int
}

// DefaultBeadFixtureSpec is the baseline fixture: 10 projects × 500 beads
// (5,000 total) with a modest amount of docgraph + sessions content. This is
// what `make bench-graphql` runs and what baseline reports compare against.
func DefaultBeadFixtureSpec() BeadFixtureSpec {
	return BeadFixtureSpec{
		Projects:                10,
		BeadsPerProject:         500,
		ClosedRatio:             0.3,
		LabelDensity:            2,
		AgentSessionsPerProject: 100, // 10 × 100 = 1,000 session rows
		DocGraphFilesPerProject: 4,
	}
}

// BeadFixture is a materialised on-disk workspace plus a live server.Server
// bound to it. Callers drive queries through Handler / State.
type BeadFixture struct {
	Spec          BeadFixtureSpec
	Server        *server.Server
	Handler       http.Handler
	Projects      []server.ProjectEntry
	TargetProject server.ProjectEntry
	TargetBeadID  string
	BeadIDsByProj map[string][]string
}

// TotalBeads returns the aggregate bead count across all seeded projects.
func (f *BeadFixture) TotalBeads() int {
	return f.Spec.Projects * f.Spec.BeadsPerProject
}

// BuildBeadFixture seeds the described workspace and returns a live fixture.
// It registers every project with the server's state so cross-project queries
// see all of them. The fixture is torn down automatically via tb.Cleanup.
func BuildBeadFixture(tb testing.TB, spec BeadFixtureSpec) *BeadFixture {
	tb.Helper()
	if spec.Projects < 1 {
		tb.Fatalf("perf: fixture needs at least 1 project, got %d", spec.Projects)
	}
	if spec.BeadsPerProject < 1 {
		tb.Fatalf("perf: fixture needs at least 1 bead per project, got %d", spec.BeadsPerProject)
	}
	if spec.LabelDensity <= 0 {
		spec.LabelDensity = 1
	}
	if spec.ClosedRatio < 0 {
		spec.ClosedRatio = 0
	}
	if spec.ClosedRatio > 1 {
		spec.ClosedRatio = 1
	}

	// Keep state out of the real user XDG dir so tests are hermetic.
	tb.Setenv("XDG_DATA_HOME", tb.TempDir())
	tb.Setenv("DDX_NODE_NAME", "ddx-perf-harness")

	root := tb.TempDir()
	projectPaths := make([]string, 0, spec.Projects)
	beadIDsByProj := make(map[string][]string, spec.Projects)
	var targetBeadID string

	for pi := 0; pi < spec.Projects; pi++ {
		projectPath := filepath.Join(root, fmt.Sprintf("project-%02d", pi))
		beads := seedProjectBeads(tb, projectPath, pi, spec)
		ids := make([]string, len(beads))
		for i, b := range beads {
			ids[i] = b.ID
		}
		beadIDsByProj[projectPath] = ids
		if spec.DocGraphFilesPerProject > 0 {
			seedProjectDocGraph(tb, projectPath, pi, spec.DocGraphFilesPerProject)
		}
		if spec.AgentSessionsPerProject > 0 {
			seedProjectSessions(tb, projectPath, pi, spec.AgentSessionsPerProject)
		}
		projectPaths = append(projectPaths, projectPath)
		if pi == spec.Projects-1 && len(beads) > 0 {
			// Target the final project's final bead so GetBeadSnapshot must
			// walk past the other (spec.Projects - 1) projects on the slow
			// path — this is what ddx-ad0db8fd cared about.
			targetBeadID = beads[len(beads)-1].ID
		}
	}

	srv := server.New(":0", projectPaths[0])
	tb.Cleanup(func() { _ = srv.Shutdown() })
	for _, p := range projectPaths[1:] {
		srv.RegisterProject(p)
	}

	projects := srv.State().GetProjects()
	if len(projects) != spec.Projects {
		tb.Fatalf("perf: registered %d projects, expected %d", len(projects), spec.Projects)
	}
	var targetProject server.ProjectEntry
	for _, proj := range projects {
		if proj.Path == projectPaths[len(projectPaths)-1] {
			targetProject = proj
			break
		}
	}
	if targetProject.ID == "" {
		tb.Fatalf("perf: target project was not registered")
	}

	return &BeadFixture{
		Spec:          spec,
		Server:        srv,
		Handler:       srv.Handler(),
		Projects:      projects,
		TargetProject: targetProject,
		TargetBeadID:  targetBeadID,
		BeadIDsByProj: beadIDsByProj,
	}
}

func seedProjectBeads(tb testing.TB, projectPath string, projectIdx int, spec BeadFixtureSpec) []bead.Bead {
	tb.Helper()
	store := bead.NewStore(filepath.Join(projectPath, ".ddx"))
	if err := store.Init(); err != nil {
		tb.Fatalf("perf: init bead store: %v", err)
	}
	baseTime := time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC)
	beads := make([]bead.Bead, 0, spec.BeadsPerProject)
	closedCutoff := int(float64(spec.BeadsPerProject) * spec.ClosedRatio)
	for bi := 0; bi < spec.BeadsPerProject; bi++ {
		id := fmt.Sprintf("ddx-perf-%02d-%04d", projectIdx, bi)
		now := baseTime.Add(time.Duration(projectIdx*spec.BeadsPerProject+bi) * time.Second)
		status := bead.StatusOpen
		if bi < closedCutoff {
			status = bead.StatusClosed
		}
		labels := make([]string, 0, spec.LabelDensity)
		for li := 0; li < spec.LabelDensity; li++ {
			labels = append(labels, fmt.Sprintf("label-%d", (bi+li)%7))
		}
		labels = append(labels, fmt.Sprintf("project-%02d", projectIdx))
		beads = append(beads, bead.Bead{
			ID:          id,
			Title:       fmt.Sprintf("Perf fixture bead %02d/%04d", projectIdx, bi),
			Status:      status,
			Priority:    bead.DefaultPriority,
			IssueType:   bead.DefaultType,
			CreatedAt:   now,
			UpdatedAt:   now,
			Labels:      labels,
			Description: "GraphQL perf fixture — realistic-shape bead with a multi-line description so parsing costs reflect typical payloads rather than artificially small bodies.",
		})
	}
	if err := store.WriteAll(beads); err != nil {
		tb.Fatalf("perf: seed bead store: %v", err)
	}
	return beads
}

func seedProjectDocGraph(tb testing.TB, projectPath string, projectIdx, count int) {
	tb.Helper()
	docsDir := filepath.Join(projectPath, "docs", "helix", "01-frame", "features")
	if err := os.MkdirAll(docsDir, 0o755); err != nil {
		tb.Fatalf("perf: mkdir docgraph: %v", err)
	}
	for di := 0; di < count; di++ {
		name := fmt.Sprintf("FEAT-%02d-%03d.md", projectIdx, di)
		path := filepath.Join(docsDir, name)
		body := fmt.Sprintf("---\nid: FEAT-%02d-%03d\ntitle: Perf fixture feature\n---\n\n# FEAT-%02d-%03d\n\nFixture body line 1\nFixture body line 2\n", projectIdx, di, projectIdx, di)
		if err := os.WriteFile(path, []byte(body), 0o644); err != nil {
			tb.Fatalf("perf: write docgraph file: %v", err)
		}
	}
}

func seedProjectSessions(tb testing.TB, projectPath string, projectIdx, count int) {
	tb.Helper()
	sessionsDir := filepath.Join(projectPath, ".ddx", "agent-logs")
	if err := os.MkdirAll(sessionsDir, 0o755); err != nil {
		tb.Fatalf("perf: mkdir sessions: %v", err)
	}
	path := filepath.Join(sessionsDir, "sessions.jsonl")
	f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if err != nil {
		tb.Fatalf("perf: open sessions.jsonl: %v", err)
	}
	defer f.Close()

	base := time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC)
	enc := json.NewEncoder(f)
	for si := 0; si < count; si++ {
		e := agent.SessionEntry{
			ID:        fmt.Sprintf("sess-%02d-%05d", projectIdx, si),
			Harness:   "claude",
			Model:     "claude-sonnet-4-6",
			Timestamp: base.Add(time.Duration(si) * time.Minute),
			Duration:  1000 + si*10,
			Correlation: map[string]string{
				"bead_id": fmt.Sprintf("ddx-perf-%02d-%04d", projectIdx, si%10),
				"effort":  "medium",
			},
		}
		if err := enc.Encode(e); err != nil {
			tb.Fatalf("perf: write session row: %v", err)
		}
	}
}

// Environment returns a short footer describing the machine the benchmark ran
// on. Included verbatim in the baseline report (ddx-9ce6842a AC §2).
func Environment() string {
	return fmt.Sprintf("go=%s goos=%s goarch=%s cpu-cores=%d", runtime.Version(), runtime.GOOS, runtime.GOARCH, runtime.NumCPU())
}

package perf

import (
	"fmt"
	"os"
	"testing"
	"time"
)

// TestGraphQLPerfMatrix_Baseline is the "measurement surface" the bead calls
// out: it seeds the default fixture, runs every Target, and — when
// DDX_BENCH_REPORT_DIR is set — writes the baseline report into that
// directory. This test is deliberately a `TestXxx` (not a `BenchmarkXxx`) so
// it runs under plain `go test` and anyone can reproduce the numbers with the
// same recipe CI will use.
//
// The acceptance criteria (ddx-9ce6842a AC §5) give per-target p95 budgets.
// This test asserts them for `bead(id:)` and `beadsByProject`; the cross-
// project `beads` target is logged but not gated, because it is the
// worst-case scan shape — a hard assertion here would tie the test to
// hardware. The markdown/JSON baseline preserves those numbers so a CI gate
// in a follow-up bead can diff against them.
func TestGraphQLPerfMatrix_Baseline(t *testing.T) {
	if testing.Short() {
		t.Skip("perf matrix skipped in -short mode")
	}
	spec := DefaultBeadFixtureSpec()
	f := BuildBeadFixture(t, spec)
	report := RunMatrix(t, f, DefaultIterations)

	for _, r := range report.Targets {
		switch r.Name {
		case "bead":
			if r.InProcess.P95 > 50 {
				t.Errorf("bead(id:) in-process p95=%.2fms > 50ms budget", r.InProcess.P95)
			}
			if r.HTTP != nil && r.HTTP.P95 > 200 {
				t.Errorf("bead(id:) HTTP p95=%.2fms > 200ms budget", r.HTTP.P95)
			}
		case "beadsByProject":
			if r.InProcess.P95 > 75 {
				t.Errorf("beadsByProject in-process p95=%.2fms > 75ms budget", r.InProcess.P95)
			}
			if r.HTTP != nil && r.HTTP.P95 > 250 {
				t.Errorf("beadsByProject HTTP p95=%.2fms > 250ms budget", r.HTTP.P95)
			}
		}
		httpLine := "n/a"
		if r.HTTP != nil {
			httpLine = fmt.Sprintf("p50=%.2fms p95=%.2fms p99=%.2fms", r.HTTP.P50, r.HTTP.P95, r.HTTP.P99)
		}
		t.Logf("target=%s iter=%d in-proc(p50=%.2fms p95=%.2fms p99=%.2fms) http(%s)",
			r.Name, r.Iterations,
			r.InProcess.P50, r.InProcess.P95, r.InProcess.P99,
			httpLine,
		)
	}

	// Optional report writing — keeps CI quick by default, lets humans
	// regenerate the baseline with `DDX_BENCH_REPORT_DIR=... go test ...`.
	if dir := os.Getenv("DDX_BENCH_REPORT_DIR"); dir != "" {
		date := os.Getenv("DDX_BENCH_REPORT_DATE")
		if date == "" {
			date = time.Now().UTC().Format("2006-01-02")
		}
		md, js, err := WriteReports(dir, date, report)
		if err != nil {
			t.Fatalf("write reports: %v", err)
		}
		t.Logf("wrote baseline report: %s (+ %s)", md, js)
	}
}

// BenchmarkGraphQLPerfMatrix is the `go test -bench` entry point. Each
// iteration runs the whole matrix so benchstat can diff runs.
func BenchmarkGraphQLPerfMatrix(b *testing.B) {
	spec := DefaultBeadFixtureSpec()
	f := BuildBeadFixture(b, spec)

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_ = RunMatrix(b, f, DefaultIterations)
	}
}

package perf

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
)

// WriteReports persists the given MatrixReport as both a human-readable
// markdown file (<dir>/<date>-baseline.md) and a machine-readable JSON sibling
// (<dir>/<date>-baseline.json). The JSON form is what a follow-up bead will
// diff in CI; the markdown is what humans read in the repo. A regression
// check (+25% on p95) is explicitly NOT wired here — the harness is the
// measurement surface, CI gating is tracked separately (ddx-9ce6842a AC §7).
func WriteReports(dir, date string, report MatrixReport) (mdPath, jsonPath string, err error) {
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return "", "", fmt.Errorf("perf: mkdir %s: %w", dir, err)
	}
	if date == "" {
		date = "baseline"
	}
	jsonPath = filepath.Join(dir, date+"-baseline.json")
	data, err := json.MarshalIndent(report, "", "  ")
	if err != nil {
		return "", "", fmt.Errorf("perf: marshal report: %w", err)
	}
	if err := os.WriteFile(jsonPath, data, 0o644); err != nil {
		return "", "", fmt.Errorf("perf: write %s: %w", jsonPath, err)
	}

	mdPath = filepath.Join(dir, date+"-baseline.md")
	if err := os.WriteFile(mdPath, []byte(renderMarkdown(report)), 0o644); err != nil {
		return "", "", fmt.Errorf("perf: write %s: %w", mdPath, err)
	}
	return mdPath, jsonPath, nil
}

func renderMarkdown(r MatrixReport) string {
	var sb strings.Builder
	fmt.Fprintf(&sb, "# GraphQL perf baseline — %s\n\n", r.GeneratedAt)
	fmt.Fprintf(&sb, "Generated by the `cli/internal/server/perf` harness (ddx-9ce6842a).\n\n")
	fmt.Fprintf(&sb, "## Fixture\n\n")
	fmt.Fprintf(&sb, "- Projects: %d\n", r.Fixture.Projects)
	fmt.Fprintf(&sb, "- Beads per project: %d\n", r.Fixture.BeadsPerProject)
	fmt.Fprintf(&sb, "- Total beads: %d\n", r.Fixture.TotalBeads)
	fmt.Fprintf(&sb, "- Agent sessions per project: %d\n\n", r.Fixture.AgentSessionsPerProject)

	fmt.Fprintf(&sb, "## Environment\n\n")
	fmt.Fprintf(&sb, "`%s`\n\n", r.Environment)

	fmt.Fprintf(&sb, "## Results (milliseconds)\n\n")
	fmt.Fprintf(&sb, "| Target | iter | in-proc p50 | in-proc p95 | in-proc p99 | HTTP p50 | HTTP p95 | HTTP p99 |\n")
	fmt.Fprintf(&sb, "|---|---:|---:|---:|---:|---:|---:|---:|\n")

	rows := make([]Result, len(r.Targets))
	copy(rows, r.Targets)
	sort.Slice(rows, func(i, j int) bool { return rows[i].Name < rows[j].Name })
	for _, row := range rows {
		httpP50, httpP95, httpP99 := "-", "-", "-"
		if row.HTTP != nil {
			httpP50 = fmt.Sprintf("%.2f", row.HTTP.P50)
			httpP95 = fmt.Sprintf("%.2f", row.HTTP.P95)
			httpP99 = fmt.Sprintf("%.2f", row.HTTP.P99)
		}
		fmt.Fprintf(&sb, "| `%s` | %d | %.2f | %.2f | %.2f | %s | %s | %s |\n",
			row.Name, row.Iterations,
			row.InProcess.P50, row.InProcess.P95, row.InProcess.P99,
			httpP50, httpP95, httpP99,
		)
	}
	fmt.Fprintf(&sb, "\n")

	fmt.Fprintf(&sb, "## Targets covered\n\n")
	fmt.Fprintf(&sb, "- `bead(id:)` — single-bead detail (shared with ddx-ad0db8fd).\n")
	fmt.Fprintf(&sb, "- `beadsByProject` — scoped list, default filter.\n")
	fmt.Fprintf(&sb, "- `beadsByProject_statusOpen` — scoped list with status filter pushdown.\n")
	fmt.Fprintf(&sb, "- `beads` (cross-project) — all-projects feed; worst-case scan.\n")
	fmt.Fprintf(&sb, "- `docGraph` — workspace doc graph build.\n")
	fmt.Fprintf(&sb, "- `agentSessions` — sessions.jsonl aggregation (shared with ddx-2ceb02fa).\n\n")

	fmt.Fprintf(&sb, "## Thresholds (ddx-9ce6842a AC §5)\n\n")
	fmt.Fprintf(&sb, "Targets on the default fixture (10 projects × 500 beads = 5,000 beads total):\n\n")
	fmt.Fprintf(&sb, "- `bead(id:)` p95 ≤ 50 ms in-process / ≤ 200 ms HTTP.\n")
	fmt.Fprintf(&sb, "- `beadsByProject(first=50)` p95 ≤ 75 ms in-process / ≤ 250 ms HTTP.\n")
	fmt.Fprintf(&sb, "- `beads(first=50)` p95 ≤ 200 ms in-process / ≤ 500 ms HTTP.\n\n")
	fmt.Fprintf(&sb, "If the scope-fix + filter-pushdown (Part 2 steps 1 and 2) do not meet these,\n")
	fmt.Fprintf(&sb, "the next step is the lightweight in-memory index (Part 2 step 3). The 2026-04-22\n")
	fmt.Fprintf(&sb, "user directive also keeps a real data store (axon / sqlite / postgres) on the\n")
	fmt.Fprintf(&sb, "table — that decision is raised to the user, not chosen unilaterally.\n\n")

	fmt.Fprintf(&sb, "## CI posture\n\n")
	fmt.Fprintf(&sb, "`make bench-graphql` regenerates this report. A +25%% p95 regression gate\n")
	fmt.Fprintf(&sb, "is proposed as a follow-up bead — the harness records thresholds here and\n")
	fmt.Fprintf(&sb, "in the JSON sibling so that gate can compare generations without re-running\n")
	fmt.Fprintf(&sb, "the full matrix against live code.\n")

	return sb.String()
}

package perf

import (
	"fmt"
	"testing"
	"time"
)

// TestBeadsListSmoke_PerProject_Under1s covers ddx-9ce6842a AC §8 (ceiling
// side). Opening the per-project `/beads` page results in a
// beadsByProject(first=50) GraphQL request — the page is interactive once
// that request returns. A generous 1 s ceiling protects against outright
// regression; the harness baseline records the real p95 for fine-grained
// tracking.
func TestBeadsListSmoke_PerProject_Under1s(t *testing.T) {
	if testing.Short() {
		t.Skip("smoke test skipped in -short mode")
	}
	spec := DefaultBeadFixtureSpec()
	f := BuildBeadFixture(t, spec)

	query := fmt.Sprintf(`{ beadsByProject(projectID: %q, first: 50) { totalCount edges { node { id title status labels } } } }`, f.TargetProject.ID)
	// Warm once so the first sample isn't a cold-cache outlier.
	if err := PostGraphQL(f.Handler, query, nil); err != nil {
		t.Fatalf("warm: %v", err)
	}

	start := time.Now()
	if err := PostGraphQL(f.Handler, query, nil); err != nil {
		t.Fatalf("query: %v", err)
	}
	elapsed := time.Since(start)
	if elapsed > time.Second {
		t.Fatalf("per-project /beads smoke: %s > 1s ceiling", elapsed)
	}
	t.Logf("per-project /beads smoke: %s (ceiling 1s)", elapsed)
}

// TestBeadsListSmoke_CrossProject_Under2s covers ddx-9ce6842a AC §8 (cross-
// project ceiling). The cross-project view calls beads(first=50) with no
// projectID, which necessarily iterates every registered project. The
// ceiling is 2 s — this is not a p95 target, it is a "the page is not
// broken" guard.
func TestBeadsListSmoke_CrossProject_Under2s(t *testing.T) {
	if testing.Short() {
		t.Skip("smoke test skipped in -short mode")
	}
	spec := DefaultBeadFixtureSpec()
	f := BuildBeadFixture(t, spec)

	query := `{ beads(first: 50) { totalCount edges { node { id title status } } } }`
	if err := PostGraphQL(f.Handler, query, nil); err != nil {
		t.Fatalf("warm: %v", err)
	}

	start := time.Now()
	if err := PostGraphQL(f.Handler, query, nil); err != nil {
		t.Fatalf("query: %v", err)
	}
	elapsed := time.Since(start)
	if elapsed > 2*time.Second {
		t.Fatalf("cross-project /beads smoke: %s > 2s ceiling", elapsed)
	}
	t.Logf("cross-project /beads smoke: %s (ceiling 2s)", elapsed)
}

// Playwright smoke test for ddx-9ce6842a AC §8.
//
// These tests measure wall-clock time from page.goto to "list is
// interactive" against a mocked GraphQL layer that returns a realistic-
// sized payload (50 beads — the default page window). They are ceilings,
// not p95 targets: the gate catches outright regressions (runaway render
// loops, missing virtualization, blocking scripts) without tying the
// repo's green/red status to machine speed.
//
// The matching server-side ceilings (GraphQL response under the same
// budget on the real fixture) are enforced in
// cli/internal/server/perf/smoke_test.go — together they guard the full
// round-trip the user feels.
import { expect, test } from '@playwright/test';

const NODE_INFO = { id: 'node-smoke', name: 'smoke node' };
const PROJECT_ID = 'proj-smoke';
const PROJECTS = [{ id: PROJECT_ID, name: 'Smoke project', path: '/repos/smoke' }];

function generateBeads(count: number) {
	const beads = [];
	for (let i = 0; i < count; i++) {
		beads.push({
			id: `ddx-smoke-${String(i).padStart(4, '0')}`,
			title: `Smoke fixture bead ${i}`,
			status: i % 3 === 0 ? 'closed' : 'open',
			priority: i % 4,
			labels: ['smoke', `bucket-${i % 7}`]
		});
	}
	return beads;
}

async function mockSmokeGraphQL(page: import('@playwright/test').Page, beadCount: number) {
	const beads = generateBeads(beadCount);
	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as { query: string };
		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
			});
		} else if (body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
				})
			});
		} else if (body.query.includes('BeadsByProject') || body.query.includes('beadsByProject')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						beadsByProject: {
							edges: beads.map((b, i) => ({ node: b, cursor: `cursor-${i}` })),
							pageInfo: { hasNextPage: false, endCursor: null },
							totalCount: beads.length
						}
					}
				})
			});
		} else if (body.query.includes('query Beads(') || body.query.includes('Beads(')) {
			// Cross-project list fetches the `beads` field.
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						beads: {
							edges: beads.map((b, i) => ({ node: b, cursor: `cursor-${i}` })),
							pageInfo: { hasNextPage: false, endCursor: null },
							totalCount: beads.length
						}
					}
				})
			});
		} else {
			await route.continue();
		}
	});
}

// ddx-9ce6842a AC §8: per-project /beads interactive within 1s.
test('smoke: /beads list is interactive within 1s on 50-bead fixture', async ({ page }) => {
	await mockSmokeGraphQL(page, 50);

	const start = Date.now();
	await page.goto(`/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/beads`);
	// "Interactive" = the heading has rendered AND at least one bead row is
	// visible (so clicking it would navigate). Both are prerequisites to a
	// real user clicking anything.
	await expect(page.getByRole('heading', { name: 'Beads' })).toBeVisible({ timeout: 1000 });
	await expect(page.getByText('Smoke fixture bead 0')).toBeVisible({ timeout: 1000 });
	const elapsed = Date.now() - start;
	expect(elapsed, `per-project /beads interactive in ${elapsed}ms (ceiling 1000ms)`).toBeLessThan(
		1000
	);
});

// ddx-9ce6842a AC §8: cross-project /beads interactive within 2s.
// We drive the same list view with 300 rows to mimic the cross-project
// aggregate load — the backend ceiling is wider (2s) because the real call
// is beads() with no projectID.
test('smoke: cross-project /beads list is interactive within 2s on 300-bead fixture', async ({
	page
}) => {
	await mockSmokeGraphQL(page, 300);

	const start = Date.now();
	await page.goto(`/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/beads`);
	await expect(page.getByRole('heading', { name: 'Beads' })).toBeVisible({ timeout: 2000 });
	await expect(page.getByText('Smoke fixture bead 0')).toBeVisible({ timeout: 2000 });
	const elapsed = Date.now() - start;
	expect(elapsed, `cross-project /beads interactive in ${elapsed}ms (ceiling 2000ms)`).toBeLessThan(
		2000
	);
});

